# Version: 1.3
#
# Changelog:
# 1.0
# - Erste lauffähige Prototyp-Installation für kienzlelock
# - LightDM-Autologin, lokaler HTTPS-Webserver, ACR122U-PC/SC-Grundlage
# - Tag-Registrierung und Toggle-Lock/Unlock als Basiskonzept
#
# 1.1
# - Native Overlay-Sperre zusätzlich zum lokalen Webserver
# - Registrierung mit Passwortschutz, PIN-Hashes und state/config-Trennung
# - Reader-Logik über kapselbares PC/SC-Backend mit ACR122U als Primärziel
#
# 1.2
# - Stabilisierung des Reader-Handlings und Entkopplung vom Firefox-Profil
# - Ausbau der Registrierungsoberfläche und Bearbeitung bestehender Tags
# - Einführung des orangefarbenen kienzlelock-Logos als Standardlogo
#
# 1.3
# - Native-only Lockscreen-Darstellung ohne sichtbaren Browser-Lockscreen
# - PIN-Eingabe vollständig nativ im Overlay, kein 1Hz-Flackern mehr
# - Logo dynamisch mit 20 Prozent Bildschirmbreite im Overlay
# - PIN-Layout: zentrierte Sperransicht, PIN-Eingabe nur im PIN-Modus rechts
# - Registrierung erweitert um Bearbeiten, Umbenennen und Löschen bestehender Tags
# - YubiKey CCID zusätzlich auf derselben PC/SC-Basis als Tag-Typ unterstützbar
# - Installer schreibt den aktuellen stabilen Patchstand konservativ aus
# ============================================================================

APP_NAME="kienzlelock"
APP_VERSION="1.3"
APP_DIR="/opt/${APP_NAME}"
ETC_DIR="/etc/${APP_NAME}"
VAR_DIR="/var/lib/${APP_NAME}"
WWW_DIR="${APP_DIR}/www"
ASSET_DIR="${WWW_DIR}/assets"
VENV_DIR="${APP_DIR}/venv"
TLS_DIR="${ETC_DIR}/tls"
AUTOSTART_DIR="/etc/xdg/autostart"
SYSTEMD_DIR="/etc/systemd/system"

if [[ "${EUID}" -ne 0 ]]; then
  echo "Bitte als root ausführen." >&2
  exit 1
fi

detect_lightdm_user() {
  if [[ -f /etc/lightdm/lightdm.conf ]]; then
    grep -E '^\s*autologin-user\s*=' /etc/lightdm/lightdm.conf | tail -n1 | awk -F= '{print $2}' | xargs || true
  fi
  if compgen -G "/etc/lightdm/lightdm.conf.d/*.conf" >/dev/null; then
    grep -h -E '^\s*autologin-user\s*=' /etc/lightdm/lightdm.conf.d/*.conf | tail -n1 | awk -F= '{print $2}' | xargs || true
  fi
}

DEFAULT_USER="$(detect_lightdm_user | tail -n1)"
if [[ -z "${DEFAULT_USER}" ]]; then
  DEFAULT_USER="${SUDO_USER:-${USER}}"
fi

read -r -p "Autologin-/XFCE-Benutzer [${DEFAULT_USER}]: " APP_USER
APP_USER="${APP_USER:-$DEFAULT_USER}"

if ! id "${APP_USER}" >/dev/null 2>&1; then
  echo "Benutzer ${APP_USER} existiert nicht." >&2
  exit 1
fi

while true; do
  read -r -s -p "Registrierungs-Passwort: " REG_PW_1
  echo
  read -r -s -p "Registrierungs-Passwort wiederholen: " REG_PW_2
  echo
  if [[ -n "${REG_PW_1}" && "${REG_PW_1}" == "${REG_PW_2}" ]]; then
    break
  fi
  echo "Passwörter leer oder ungleich. Bitte erneut." >&2
done

export REG_PW_1
REG_HASH="$(python3 - <<'PY'
import hashlib, os, secrets
pw = os.environ['REG_PW_1']
salt = secrets.token_hex(16)
iterations = 200_000
digest = hashlib.pbkdf2_hmac('sha256', pw.encode(), salt.encode(), iterations).hex()
print(f'pbkdf2_sha256${iterations}${salt}${digest}')
PY
)"
unset REG_PW_1 REG_PW_2

export DEBIAN_FRONTEND=noninteractive
apt-get update
apt-get install -y \
  python3 python3-venv python3-dev python3-tk \
  build-essential swig \
  openssl curl jq \
  firefox lightdm xfce4 \
  x11-xserver-utils xdotool wmctrl \
  pcscd pcsc-tools libccid \
  python3-pil || true
apt-get install -y python3-pil.imagetk || true

mkdir -p "${APP_DIR}" "${WWW_DIR}" "${ASSET_DIR}" "${ETC_DIR}" "${VAR_DIR}" "${TLS_DIR}"

python3 -m venv --system-site-packages "${VENV_DIR}"
"${VENV_DIR}/bin/pip" install --upgrade pip setuptools wheel >/dev/null
if ! "${VENV_DIR}/bin/python" -c "import smartcard" >/dev/null 2>&1; then
  if apt-cache show python3-pyscard >/dev/null 2>&1; then
    apt-get install -y python3-pyscard
  else
    apt-get install -y libpcsclite-dev pcscd libccid
    "${VENV_DIR}/bin/pip" install pyscard
  fi
fi

openssl req -x509 -nodes -newkey rsa:2048 \
  -keyout "${TLS_DIR}/key.pem" \
  -out "${TLS_DIR}/cert.pem" \
  -days 3650 \
  -subj "/CN=127.0.0.1" >/dev/null 2>&1
chmod 600 "${TLS_DIR}/key.pem"
chmod 644 "${TLS_DIR}/cert.pem"

cat > "${APP_DIR}/VERSION" <<'EOF'
1.3
EOF

base64 -d > "${ASSET_DIR}/kienzlelock-logo.png" <<'EOF'

EOF
chmod 644 "${ASSET_DIR}/kienzlelock-logo.png"

export REG_HASH
python3 - <<'PY'
import json, os
config = {
  'mode': 'local',
  'local': {'bind': '127.0.0.1', 'port': 8443, 'tls_cert': '/etc/kienzlelock/tls/cert.pem', 'tls_key': '/etc/kienzlelock/tls/key.pem'},
  'tls_cert': '/etc/kienzlelock/tls/cert.pem',
  'tls_key': '/etc/kienzlelock/tls/key.pem',
  'central': {'base_url': '', 'timeout_ms': 2000, 'verify_tls': True, 'endpoints': {'resolve_tag': '/api/kienzlelock/resolve_tag', 'verify_pin': '/api/kienzlelock/verify_pin'}},
  'admin': {'registration_password_hash': os.environ['REG_HASH'], 'session_ttl_seconds': 900, 'registration_window_seconds': 120},
  'policy': {'default_reauth_after_seconds': 28800, 'max_pin_attempts': 4, 'lockout_seconds': 600, 'lock_check_interval_ms': 250},
  'reader': {'backend': 'acr122u_pcsc', 'reader_name_contains': 'ACR122', 'acr122_reader_name_contains': 'ACR122', 'enable_yubikey_ccid': True, 'yubikey_reader_name_contains': 'Yubico YubiKey', 'poll_interval_ms': 100, 'stable_reads_required': 2, 'absent_rearm_ms': 250, 'reader_error_backoff_ms': 400},
  'users': {},
}
state = {
  'lock': {'authenticated': True, 'active_user': None, 'last_auth_ts': 0, 'reauth_required': False},
  'auth': {'current_tag_id': None, 'current_user': None, 'failed_attempts': 0, 'locked_until_ts': 0},
  'registration': {'active': False, 'expires_at': 0, 'pending_tag': None, 'admin_session_valid': False},
  'reader': {'backend': 'acr122u_pcsc', 'online': False, 'reader_name': None, 'last_seen_tag': None, 'last_seen_ts': 0, 'last_error': None},
  'ui': {'screen': 'locked', 'message': 'System gesperrt: Bitte Karte.'},
}
for path, payload in (("/etc/kienzlelock/config.json", config), ("/var/lib/kienzlelock/state.json", state)):
    with open(path, 'w', encoding='utf-8') as handle:
        json.dump(payload, handle, indent=2)
        handle.write('\n')
PY
chmod 600 "${ETC_DIR}/config.json"
chmod 644 "${VAR_DIR}/state.json"

cat > "${APP_DIR}/daemon.py" <<'PYEOF'
#!/usr/bin/env python3
import json
import logging
import os
import secrets
import signal
import ssl
import tempfile
import threading
import time
import urllib.request
from http import HTTPStatus
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from pathlib import Path
from typing import Any, Dict, Optional

CONFIG_PATH = Path('/etc/kienzlelock/config.json')
STATE_PATH = Path('/var/lib/kienzlelock/state.json')
VERSION_PATH = Path('/opt/kienzlelock/VERSION')
WWW_PATH = Path('/opt/kienzlelock/www')
LOG = logging.getLogger('kienzlelockd')
VERSION = '1.3'

try:
    from smartcard.Exceptions import CardConnectionException, NoCardException
    from smartcard.System import readers as pcsc_readers
except Exception:  # pragma: no cover
    CardConnectionException = Exception
    NoCardException = Exception
    pcsc_readers = None


def now_ts() -> int:
    return int(time.time())


def atomic_write_json(path: Path, payload: Dict[str, Any], mode: int = 0o600) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    fd, tmp_name = tempfile.mkstemp(prefix=path.name + '.', dir=str(path.parent))
    try:
        with os.fdopen(fd, 'w', encoding='utf-8') as handle:
            json.dump(payload, handle, indent=2)
            handle.write('\n')
        os.chmod(tmp_name, mode)
        os.replace(tmp_name, path)
    finally:
        if os.path.exists(tmp_name):
            try:
                os.unlink(tmp_name)
            except OSError:
                pass


def load_json(path: Path, default: Dict[str, Any]) -> Dict[str, Any]:
    if not path.exists():
        return json.loads(json.dumps(default))
    with path.open('r', encoding='utf-8') as handle:
        return json.load(handle)


def default_config() -> Dict[str, Any]:
    return {
        'mode': 'local',
        'local': {
            'bind': '127.0.0.1',
            'port': 8443,
            'tls_cert': '/etc/kienzlelock/tls/cert.pem',
            'tls_key': '/etc/kienzlelock/tls/key.pem',
        },
        'tls_cert': '/etc/kienzlelock/tls/cert.pem',
        'tls_key': '/etc/kienzlelock/tls/key.pem',
        'central': {
            'base_url': '',
            'timeout_ms': 2000,
            'verify_tls': True,
            'endpoints': {
                'resolve_tag': '/api/kienzlelock/resolve_tag',
                'verify_pin': '/api/kienzlelock/verify_pin',
            },
        },
        'admin': {
            'registration_password_hash': '',
            'session_ttl_seconds': 900,
            'registration_window_seconds': 120,
        },
        'policy': {
            'default_reauth_after_seconds': 28800,
            'max_pin_attempts': 4,
            'lockout_seconds': 600,
            'lock_check_interval_ms': 250,
        },
        'reader': {
            'backend': 'acr122u_pcsc',
            'reader_name_contains': 'ACR122',
            'acr122_reader_name_contains': 'ACR122',
            'enable_yubikey_ccid': True,
            'yubikey_reader_name_contains': 'Yubico YubiKey',
            'poll_interval_ms': 100,
            'stable_reads_required': 2,
            'absent_rearm_ms': 250,
            'reader_error_backoff_ms': 400,
        },
        'users': {},
    }


def default_state() -> Dict[str, Any]:
    return {
        'lock': {
            'authenticated': True,
            'active_user': None,
            'last_auth_ts': 0,
            'reauth_required': False,
        },
        'auth': {
            'current_tag_id': None,
            'current_user': None,
            'failed_attempts': 0,
            'locked_until_ts': 0,
        },
        'registration': {
            'active': False,
            'expires_at': 0,
            'pending_tag': None,
            'admin_session_valid': False,
        },
        'reader': {
            'backend': 'acr122u_pcsc',
            'online': False,
            'reader_name': None,
            'last_seen_tag': None,
            'last_seen_ts': 0,
            'last_error': None,
        },
        'ui': {
            'screen': 'locked',
            'message': 'System gesperrt: Bitte Karte.',
        },
    }


def deep_merge(dst: Dict[str, Any], src: Dict[str, Any]) -> Dict[str, Any]:
    for key, value in src.items():
        if isinstance(value, dict):
            if key not in dst or not isinstance(dst[key], dict):
                dst[key] = {}
            deep_merge(dst[key], value)
        else:
            dst.setdefault(key, value)
    return dst


def ensure_config_shape(config: Dict[str, Any]) -> Dict[str, Any]:
    config = deep_merge(config, default_config())
    if not config.get('local', {}).get('tls_cert'):
        config['local']['tls_cert'] = config.get('tls_cert') or '/etc/kienzlelock/tls/cert.pem'
    if not config.get('local', {}).get('tls_key'):
        config['local']['tls_key'] = config.get('tls_key') or '/etc/kienzlelock/tls/key.pem'
    config['tls_cert'] = config['local']['tls_cert']
    config['tls_key'] = config['local']['tls_key']
    if not isinstance(config.get('users'), dict):
        config['users'] = {}
    return config


def ensure_state_shape(state: Dict[str, Any]) -> Dict[str, Any]:
    return deep_merge(state, default_state())


def normalize_tag_value(value: Optional[str]) -> Optional[str]:
    if value is None:
        return None
    return ''.join(ch for ch in str(value).upper() if ch.isalnum())


def make_hash(secret: str, salt: Optional[str] = None, iterations: int = 200_000) -> str:
    import hashlib

    salt = salt or secrets.token_hex(16)
    digest = hashlib.pbkdf2_hmac(
        'sha256',
        secret.encode('utf-8'),
        salt.encode('utf-8'),
        iterations,
    ).hex()
    return f'pbkdf2_sha256${iterations}${salt}${digest}'


def verify_hash(secret: str, encoded: str) -> bool:
    import hashlib
    import hmac

    try:
        algo, iterations, salt, digest = encoded.split('$', 3)
        if algo != 'pbkdf2_sha256':
            return False
        candidate = hashlib.pbkdf2_hmac(
            'sha256',
            secret.encode('utf-8'),
            salt.encode('utf-8'),
            int(iterations),
        ).hex()
        return hmac.compare_digest(candidate, digest)
    except Exception:
        return False


def read_body(handler: BaseHTTPRequestHandler) -> Dict[str, Any]:
    length = int(handler.headers.get('Content-Length', '0'))
    if length <= 0:
        return {}
    raw = handler.rfile.read(length)
    if not raw:
        return {}
    return json.loads(raw.decode('utf-8'))


class LocalAuthProvider:
    def __init__(self, runtime: 'KienzleLockRuntime') -> None:
        self.runtime = runtime

    def resolve_token(self, token: Dict[str, Any]) -> Dict[str, Any]:
        token_type = str(token.get('type') or '').strip().lower()
        token_value = normalize_tag_value(token.get('value'))
        config = self.runtime.config
        state = self.runtime.state

        for user_id, user in config.get('users', {}).items():
            for tag in user.get('tags', []):
                if str(tag.get('type', 'uid_hex')).strip().lower() != token_type:
                    continue
                if normalize_tag_value(tag.get('value')) != token_value:
                    continue

                display_name = user.get('display_name') or user_id
                reauth_after = int(
                    tag.get('reauth_after_seconds')
                    or config.get('policy', {}).get('default_reauth_after_seconds', 28800)
                )
                reauth_valid = (
                    state['lock'].get('active_user') == user_id
                    and int(state['lock'].get('last_auth_ts') or 0) > 0
                    and (time.time() - int(state['lock']['last_auth_ts'])) <= reauth_after
                )
                return {
                    'known': True,
                    'user_id': user_id,
                    'display_name': display_name,
                    'tag_id': tag.get('id'),
                    'tag': tag,
                    'pin_required': bool(tag.get('pin_hash')),
                    'pin_hash': tag.get('pin_hash', ''),
                    'reauth_after_seconds': reauth_after,
                    'reauth_valid': reauth_valid,
                }

        return {
            'known': False,
            'pin_required': False,
            'reauth_valid': False,
        }

    def verify_pin(self, user_id: str, tag_id: str, pin: str) -> Dict[str, Any]:
        user = self.runtime.config.get('users', {}).get(user_id)
        if not user:
            return {'ok': False, 'error': 'unknown_user'}
        for tag in user.get('tags', []):
            if str(tag.get('id')) != str(tag_id):
                continue
            pin_hash = tag.get('pin_hash', '')
            if not pin_hash:
                return {'ok': True}
            return {'ok': verify_hash(pin, pin_hash)}
        return {'ok': False, 'error': 'unknown_tag'}


class CentralAuthProvider:
    def __init__(self, runtime: 'KienzleLockRuntime') -> None:
        self.runtime = runtime

    def _post_json(self, endpoint_key: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        central = self.runtime.config.get('central', {})
        base_url = str(central.get('base_url') or '').rstrip('/')
        endpoint = str(central.get('endpoints', {}).get(endpoint_key) or '').strip()
        if not base_url or not endpoint:
            raise RuntimeError('central.base_url oder central.endpoints fehlen')
        url = base_url + endpoint
        request = urllib.request.Request(
            url,
            data=json.dumps(payload).encode('utf-8'),
            method='POST',
            headers={'Content-Type': 'application/json'},
        )
        ctx = None
        if central.get('verify_tls', True) is False:
            ctx = ssl._create_unverified_context()
        with urllib.request.urlopen(
            request,
            timeout=max(0.2, int(central.get('timeout_ms', 2000)) / 1000.0),
            context=ctx,
        ) as response:
            return json.loads(response.read().decode('utf-8'))

    def resolve_token(self, token: Dict[str, Any]) -> Dict[str, Any]:
        try:
            return self._post_json('resolve_tag', token)
        except Exception as exc:
            LOG.warning('Central resolve fehlgeschlagen: %s', exc)
            return {'known': False, 'error': 'central_unavailable'}

    def verify_pin(self, user_id: str, tag_id: str, pin: str) -> Dict[str, Any]:
        try:
            return self._post_json('verify_pin', {
                'user_id': user_id,
                'tag_id': tag_id,
                'pin': pin,
            })
        except Exception as exc:
            LOG.warning('Central PIN-Prüfung fehlgeschlagen: %s', exc)
            return {'ok': False, 'error': 'central_unavailable'}


class PcscAcr122Reader(threading.Thread):
    def __init__(self, runtime: 'KienzleLockRuntime') -> None:
        super().__init__(daemon=True, name='pcsc-reader')
        self.runtime = runtime
        self.stop_event = threading.Event()
        self.reader_states: Dict[str, Dict[str, Any]] = {}

    def stop(self) -> None:
        self.stop_event.set()

    def _cfg_int(self, key: str, default: int, minimum: int) -> int:
        try:
            value = int(self.runtime.config.get('reader', {}).get(key, default))
        except Exception:
            value = default
        return max(minimum, value)

    def _cfg_bool(self, key: str, default: bool) -> bool:
        value = self.runtime.config.get('reader', {}).get(key, default)
        if isinstance(value, bool):
            return value
        return str(value).strip().lower() in ('1', 'true', 'yes', 'on')

    def _normalize_hex(self, values) -> str:
        return normalize_tag_value(''.join(f'{int(v):02X}' for v in values or []))

    def _reader_state(self, key: str) -> Dict[str, Any]:
        state = self.reader_states.get(key)
        if state is None:
            state = {
                'present_token': None,
                'stable_reads': 0,
                'absent_since_monotonic': None,
                'rearmed': True,
            }
            self.reader_states[key] = state
        return state

    def _iter_candidate_readers(self):
        if pcsc_readers is None:
            raise RuntimeError('smartcard/PySCard nicht verfügbar')

        available = list(pcsc_readers())
        cfg = self.runtime.config.get('reader', {})
        acr_filter = str(cfg.get('acr122_reader_name_contains') or cfg.get('reader_name_contains') or 'ACR122').strip().lower()
        yk_filter = str(cfg.get('yubikey_reader_name_contains') or 'Yubico YubiKey').strip().lower()
        enable_yubikey = self._cfg_bool('enable_yubikey_ccid', True)

        result = []
        for reader in available:
            name = str(reader)
            lname = name.lower()
            if acr_filter and acr_filter in lname:
                result.append(('acr122', reader))
                continue
            if enable_yubikey and yk_filter and yk_filter in lname:
                result.append(('yubikey', reader))
                continue

        if not result:
            for reader in available:
                lname = str(reader).lower()
                if 'picc' in lname or 'acr122' in lname:
                    result.append(('acr122', reader))
                elif enable_yubikey and ('yubico' in lname or 'yubikey' in lname):
                    result.append(('yubikey', reader))

        return result

    def _mark_absent_if_due(self, reader_key: str, absent_rearm_s: float) -> None:
        state = self._reader_state(reader_key)
        now = time.monotonic()
        if state['absent_since_monotonic'] is None:
            state['absent_since_monotonic'] = now
        if (now - state['absent_since_monotonic']) >= absent_rearm_s:
            state['present_token'] = None
            state['stable_reads'] = 0
            state['rearmed'] = True

    def _mark_present(self, reader_key: str, token: Dict[str, Any], stable_reads_required: int) -> bool:
        state = self._reader_state(reader_key)
        token_id = f"{token.get('type','')}:{token.get('value','')}"
        state['absent_since_monotonic'] = None
        if state['present_token'] != token_id:
            state['present_token'] = token_id
            state['stable_reads'] = 1
        else:
            state['stable_reads'] += 1
        if state['rearmed'] and state['stable_reads'] >= stable_reads_required:
            state['rearmed'] = False
            self.runtime.on_tag_seen(token)
            return True
        return False

    def _read_acr122_token(self, reader):
        connection = reader.createConnection()
        connection.connect()
        data, sw1, sw2 = connection.transmit([0xFF, 0xCA, 0x00, 0x00, 0x00])
        if (sw1, sw2) != (0x90, 0x00) or not data:
            return None
        uid = self._normalize_hex(data)
        if not uid:
            return None
        return {'type': 'uid_hex', 'value': uid, 'label': uid}

    def _read_yubikey_token(self, reader):
        connection = reader.createConnection()
        connection.connect()
        atr = connection.getATR()
        atr_hex = self._normalize_hex(atr)
        if not atr_hex:
            return None
        short = atr_hex[-12:] if len(atr_hex) > 12 else atr_hex
        return {'type': 'yubikey_ccid_atr', 'value': atr_hex, 'label': f'YubiKey {short}'}

    def run(self) -> None:
        poll_s = max(0.05, self._cfg_int('poll_interval_ms', 100, 50) / 1000.0)
        stable_reads_required = self._cfg_int('stable_reads_required', 2, 1)
        absent_rearm_s = max(0.05, self._cfg_int('absent_rearm_ms', 250, 50) / 1000.0)
        reader_error_backoff_s = max(0.10, self._cfg_int('reader_error_backoff_ms', 400, 100) / 1000.0)

        while not self.stop_event.is_set():
            try:
                candidates = self._iter_candidate_readers()
                if not candidates:
                    self.runtime.update_reader_status(online=False, reader_name=None, last_error='Kein passender PC/SC-Reader gefunden')
                    time.sleep(1.0)
                    continue

                self.runtime.update_reader_status(
                    online=True,
                    reader_name='; '.join(str(reader) for _, reader in candidates),
                    last_error=None,
                )

                for kind, reader in candidates:
                    reader_key = f'{kind}:{reader}'
                    try:
                        if kind == 'acr122':
                            token = self._read_acr122_token(reader)
                        elif kind == 'yubikey':
                            token = self._read_yubikey_token(reader)
                        else:
                            token = None

                        if token:
                            emitted = self._mark_present(reader_key, token, stable_reads_required)
                            if emitted:
                                break
                        else:
                            self._mark_absent_if_due(reader_key, absent_rearm_s)
                    except NoCardException:
                        self._mark_absent_if_due(reader_key, absent_rearm_s)
                    except CardConnectionException as exc:
                        self.runtime.update_reader_status(last_error=f'{reader}: {exc}', online=True)
                        self._mark_absent_if_due(reader_key, absent_rearm_s)

                time.sleep(poll_s)
            except Exception as exc:
                self.runtime.update_reader_status(last_error=str(exc), online=False)
                LOG.exception('Reader-Fehler')
                time.sleep(reader_error_backoff_s)


class KienzleLockRuntime:
    def __init__(self) -> None:
        self.lock = threading.RLock()
        self.config = ensure_config_shape(load_json(CONFIG_PATH, default_config()))
        self.state = ensure_state_shape(load_json(STATE_PATH, default_state()))
        self.admin_tokens: Dict[str, int] = {}
        self.stop_event = threading.Event()

        if self.state['ui'].get('screen') == 'pin' and not self.state['lock'].get('authenticated'):
            self.state['ui']['screen'] = 'locked'
            self.state['ui']['message'] = 'System gesperrt: Bitte Karte.'
            self.state['auth']['current_tag_id'] = None
            self.state['auth']['current_user'] = None
            self.state['lock']['reauth_required'] = False

        mode = self.config.get('mode', 'local')
        self.auth_provider = LocalAuthProvider(self) if mode == 'local' else CentralAuthProvider(self)

        backend = self.config.get('reader', {}).get('backend', 'acr122u_pcsc')
        if backend == 'acr122u_pcsc':
            self.reader_backend = PcscAcr122Reader(self)
        else:
            raise RuntimeError(f'Unbekanntes Reader-Backend: {backend}')

        self.housekeeper = threading.Thread(target=self._housekeeper_loop, name='housekeeper', daemon=True)
        self.persist_config()
        self.persist_state()

    def start(self) -> None:
        self.reader_backend.start()
        self.housekeeper.start()

    def stop(self) -> None:
        self.stop_event.set()
        self.reader_backend.stop()

    def persist_config(self) -> None:
        with self.lock:
            atomic_write_json(CONFIG_PATH, self.config, 0o600)

    def persist_state(self) -> None:
        with self.lock:
            atomic_write_json(STATE_PATH, self.state, 0o644)

    def issue_admin_token(self) -> str:
        token = secrets.token_urlsafe(32)
        ttl = int(self.config.get('admin', {}).get('session_ttl_seconds', 900))
        self.admin_tokens[token] = now_ts() + ttl
        self.state['registration']['admin_session_valid'] = True
        self.persist_state()
        return token

    def _validate_admin_token(self, token: str) -> bool:
        expires_at = int(self.admin_tokens.get(token, 0) or 0)
        return bool(token) and expires_at > now_ts()

    def update_reader_status(self, online: Optional[bool] = None, reader_name: Optional[str] = None, last_error: Optional[str] = None) -> None:
        changed = False
        with self.lock:
            reader = self.state['reader']
            if online is not None and reader.get('online') != bool(online):
                reader['online'] = bool(online)
                changed = True
            if reader_name is not None and reader.get('reader_name') != reader_name:
                reader['reader_name'] = reader_name
                changed = True
            if last_error is not None and reader.get('last_error') != last_error:
                reader['last_error'] = last_error
                changed = True
            if changed:
                self.persist_state()

    def _find_tag_record(self, tag_id: str = '', tag_type: str = '', tag_value: str = ''):
        tag_id = str(tag_id or '').strip()
        tag_type = str(tag_type or '').strip().lower()
        tag_value = normalize_tag_value(tag_value)
        for user_id, user in self.config.get('users', {}).items():
            for idx, tag in enumerate(user.get('tags', [])):
                if tag_id and str(tag.get('id', '')).strip() == tag_id:
                    return user_id, user, idx, tag
                if tag_type and str(tag.get('type', 'uid_hex')).strip().lower() == tag_type and normalize_tag_value(tag.get('value')) == tag_value:
                    return user_id, user, idx, tag
        return None, None, None, None

    def _clear_pending_auth(self) -> None:
        self.state['auth']['current_tag_id'] = None
        self.state['auth']['current_user'] = None
        self.state['lock']['reauth_required'] = False

    def _lock_now(self) -> None:
        self.state['lock']['authenticated'] = False
        self.state['lock']['active_user'] = None
        self.state['lock']['reauth_required'] = False
        self.state['ui']['screen'] = 'locked'
        self.state['ui']['message'] = 'System gesperrt: Bitte Karte.'
        self._clear_pending_auth()

    def _unlock_now(self, user_id: str, display_name: str) -> None:
        self.state['lock']['authenticated'] = True
        self.state['lock']['active_user'] = user_id
        self.state['lock']['last_auth_ts'] = now_ts()
        self.state['lock']['reauth_required'] = False
        self.state['auth']['failed_attempts'] = 0
        self.state['auth']['locked_until_ts'] = 0
        self.state['ui']['screen'] = 'locked'
        self.state['ui']['message'] = f'Hallo {display_name}! Vielen Dank!'
        self._clear_pending_auth()

    def on_tag_seen(self, token: Dict[str, Any]) -> None:
        with self.lock:
            token_type = str(token.get('type', '')).strip().lower()
            token_value = normalize_tag_value(token.get('value')) or ''
            self.state['reader']['backend'] = self.config.get('reader', {}).get('backend', 'acr122u_pcsc')
            self.state['reader']['last_seen_tag'] = token_value
            self.state['reader']['last_seen_ts'] = now_ts()

            if self.state['registration'].get('active') and self.state['registration'].get('admin_session_valid'):
                self.state['registration']['pending_tag'] = {
                    'type': token_type,
                    'value': token_value,
                    'label': token.get('label') or token_value,
                }
                self.state['ui']['screen'] = 'locked'
                self.state['ui']['message'] = 'Tag erkannt. Bitte in der Registrierung speichern.'
                self.persist_state()
                return

            if int(self.state['auth'].get('locked_until_ts') or 0) > now_ts():
                self.state['ui']['screen'] = 'locked'
                self.state['ui']['message'] = 'Zu viele Fehlversuche.'
                self.persist_state()
                return

            resolved = self.auth_provider.resolve_token(token)
            if not resolved.get('known'):
                self.persist_state()
                return

            if self.state['lock'].get('authenticated'):
                self._lock_now()
                self.persist_state()
                return

            display_name = resolved.get('display_name') or resolved.get('user_id') or 'Benutzer'
            if resolved.get('reauth_valid') or not resolved.get('pin_required'):
                self._unlock_now(resolved['user_id'], display_name)
                self.persist_state()
                return

            self.state['lock']['authenticated'] = False
            self.state['lock']['active_user'] = None
            self.state['lock']['reauth_required'] = True
            self.state['auth']['current_tag_id'] = resolved.get('tag_id')
            self.state['auth']['current_user'] = resolved.get('user_id')
            self.state['ui']['screen'] = 'pin'
            self.state['ui']['message'] = f'Hallo {display_name}! Vielen Dank!'
            self.persist_state()

    def submit_pin(self, pin: str) -> Dict[str, Any]:
        with self.lock:
            now = now_ts()
            locked_until_ts = int(self.state['auth'].get('locked_until_ts') or 0)
            if locked_until_ts > now:
                return {'ok': False, 'error': 'locked_out', 'locked_until_ts': locked_until_ts}

            user_id = self.state['auth'].get('current_user')
            tag_id = self.state['auth'].get('current_tag_id')
            if not user_id or not tag_id:
                return {'ok': False, 'error': 'no_pending_pin'}

            verification = self.auth_provider.verify_pin(str(user_id), str(tag_id), str(pin))
            if verification.get('ok'):
                user = self.config.get('users', {}).get(str(user_id), {})
                display_name = user.get('display_name') or str(user_id)
                self._unlock_now(str(user_id), display_name)
                self.persist_state()
                return {'ok': True, 'authenticated': True}

            failed_attempts = int(self.state['auth'].get('failed_attempts') or 0) + 1
            self.state['auth']['failed_attempts'] = failed_attempts
            max_attempts = int(self.config.get('policy', {}).get('max_pin_attempts', 4))
            if failed_attempts >= max_attempts:
                lockout_seconds = int(self.config.get('policy', {}).get('lockout_seconds', 600))
                self.state['auth']['locked_until_ts'] = now + lockout_seconds
                self.state['ui']['screen'] = 'locked'
                self.state['ui']['message'] = 'Zu viele Fehlversuche.'
                self._clear_pending_auth()
                self.persist_state()
                return {'ok': False, 'error': 'locked_out', 'locked_until_ts': self.state['auth']['locked_until_ts']}

            self.state['ui']['screen'] = 'pin'
            self.state['ui']['message'] = 'PIN falsch. Bitte erneut.'
            self.persist_state()
            return {'ok': False, 'error': 'invalid_pin', 'failed_attempts': failed_attempts}

    def admin_login(self, password: str) -> Dict[str, Any]:
        encoded = str(self.config.get('admin', {}).get('registration_password_hash') or '')
        if not encoded or not verify_hash(password, encoded):
            self.state['registration']['admin_session_valid'] = False
            self.persist_state()
            return {'ok': False, 'error': 'invalid_password'}
        token = self.issue_admin_token()
        return {'ok': True, 'token': token}

    def registration_start(self, token: str) -> Dict[str, Any]:
        with self.lock:
            if not self._validate_admin_token(token):
                return {'ok': False, 'error': 'unauthorized'}
            ttl = int(self.config.get('admin', {}).get('registration_window_seconds', 120))
            self.state['registration']['active'] = True
            self.state['registration']['expires_at'] = now_ts() + ttl
            self.state['registration']['pending_tag'] = None
            self.state['registration']['admin_session_valid'] = True
            self.state['ui']['message'] = 'Bitte jetzt neuen Tag gegenhalten.'
            self.persist_state()
            return {'ok': True}

    def registration_cancel(self, token: str) -> Dict[str, Any]:
        with self.lock:
            if not self._validate_admin_token(token):
                return {'ok': False, 'error': 'unauthorized'}
            self.state['registration']['active'] = False
            self.state['registration']['expires_at'] = 0
            self.state['registration']['pending_tag'] = None
            self.state['registration']['admin_session_valid'] = True
            self.state['ui']['message'] = 'System gesperrt: Bitte Karte.'
            self.persist_state()
            return {'ok': True}

    def registration_commit(self, token: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        with self.lock:
            if not self._validate_admin_token(token):
                return {'ok': False, 'error': 'unauthorized'}
            pending_tag = self.state['registration'].get('pending_tag')
            if not self.state['registration'].get('active') or not pending_tag:
                return {'ok': False, 'error': 'no_pending_tag'}

            user_id = str(payload.get('user_id', '')).strip()
            display_name = str(payload.get('display_name', '')).strip() or user_id
            label = str(payload.get('label', '')).strip() or pending_tag.get('label') or pending_tag.get('value')
            pin = str(payload.get('pin', '')).strip()
            if not user_id:
                return {'ok': False, 'error': 'user_id_required'}
            if not pin:
                return {'ok': False, 'error': 'pin_required'}

            existing = self._find_tag_record(tag_type=pending_tag.get('type', ''), tag_value=pending_tag.get('value', ''))
            if existing[3] is not None:
                return {'ok': False, 'error': 'tag_exists'}

            tag = {
                'id': secrets.token_hex(8),
                'type': str(pending_tag.get('type') or 'uid_hex'),
                'value': normalize_tag_value(pending_tag.get('value')),
                'label': label,
                'pin_hash': make_hash(pin),
            }
            reauth = payload.get('reauth_after_seconds')
            if str(reauth).strip() != '':
                tag['reauth_after_seconds'] = int(reauth)

            user = self.config.setdefault('users', {}).setdefault(user_id, {'display_name': display_name, 'tags': []})
            user['display_name'] = display_name
            user.setdefault('tags', []).append(tag)

            self.state['registration']['active'] = False
            self.state['registration']['expires_at'] = 0
            self.state['registration']['pending_tag'] = None
            self.state['registration']['admin_session_valid'] = True
            self.state['ui']['message'] = 'Registrierung gespeichert.'
            self.persist_config()
            self.persist_state()
            return {'ok': True, 'tag_id': tag['id']}

    def _admin_registration_rows(self):
        rows = []
        for user_id, user in self.config.get('users', {}).items():
            display_name = user.get('display_name', user_id)
            tags = user.get('tags', [])
            for tag in tags:
                rows.append({
                    'tag_id': tag.get('id'),
                    'user_id': user_id,
                    'display_name': display_name,
                    'type': tag.get('type', 'uid_hex'),
                    'value': tag.get('value', ''),
                    'label': tag.get('label', ''),
                    'reauth_after_seconds': tag.get('reauth_after_seconds', ''),
                    'user_tag_count': len(tags),
                })
        rows.sort(key=lambda r: (
            str(r.get('display_name', '')).lower(),
            str(r.get('user_id', '')).lower(),
            str(r.get('label', '')).lower(),
            str(r.get('value', '')).lower(),
        ))
        return rows

    def admin_status(self, token: str) -> Dict[str, Any]:
        base = self.public_state()
        authorized = self._validate_admin_token(token)
        base['admin_authorized'] = authorized
        base['registrations'] = self._admin_registration_rows() if authorized else []
        return base

    def registration_update(self, token: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        with self.lock:
            if not self._validate_admin_token(token):
                return {'ok': False, 'error': 'unauthorized'}

            tag_id = str(payload.get('tag_id', '')).strip()
            if not tag_id:
                return {'ok': False, 'error': 'tag_id_required'}

            current_user_id, current_user, tag_index, tag = self._find_tag_record(tag_id=tag_id)
            if not tag:
                return {'ok': False, 'error': 'tag_not_found'}

            target_user_id = str(payload.get('user_id', '')).strip() or current_user_id
            display_name = str(payload.get('display_name', '')).strip() or current_user.get('display_name', target_user_id) or target_user_id
            label = str(payload.get('label', '')).strip() or tag.get('label') or tag.get('value') or tag_id
            pin = str(payload.get('pin', '')).strip()
            reauth_raw = payload.get('reauth_after_seconds', None)

            working_tag = dict(tag)
            working_tag['label'] = label
            if pin:
                working_tag['pin_hash'] = make_hash(pin)
            if reauth_raw is not None:
                if str(reauth_raw).strip() == '':
                    working_tag.pop('reauth_after_seconds', None)
                else:
                    working_tag['reauth_after_seconds'] = int(reauth_raw)

            if target_user_id != current_user_id:
                current_user.setdefault('tags', []).pop(tag_index)
                if not current_user.get('tags'):
                    self.config.get('users', {}).pop(current_user_id, None)
                target_user = self.config.setdefault('users', {}).setdefault(target_user_id, {'display_name': display_name, 'tags': []})
                target_user.setdefault('tags', []).append(working_tag)
            else:
                target_user = current_user
                current_user.setdefault('tags', [])[tag_index] = working_tag

            target_user['display_name'] = display_name
            self.state['ui']['message'] = 'Registrierung aktualisiert.'
            self.persist_config()
            self.persist_state()
            return {'ok': True, 'tag_id': working_tag.get('id'), 'user_id': target_user_id}

    def registration_delete(self, token: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        with self.lock:
            if not self._validate_admin_token(token):
                return {'ok': False, 'error': 'unauthorized'}

            tag_id = str(payload.get('tag_id', '')).strip()
            if not tag_id:
                return {'ok': False, 'error': 'tag_id_required'}

            user_id, user, tag_index, tag = self._find_tag_record(tag_id=tag_id)
            if not tag:
                return {'ok': False, 'error': 'tag_not_found'}

            user.setdefault('tags', []).pop(tag_index)
            if not user.get('tags'):
                self.config.get('users', {}).pop(user_id, None)

            self.state['ui']['message'] = 'Registrierung gelöscht.'
            self.persist_config()
            self.persist_state()
            return {'ok': True, 'tag_id': tag_id, 'user_id': user_id}

    def public_state(self) -> Dict[str, Any]:
        with self.lock:
            users = [
                {'user_id': user_id, 'display_name': user.get('display_name', user_id)}
                for user_id, user in sorted(self.config.get('users', {}).items())
            ]
            return {
                'version': VERSION,
                'state': self.state,
                'config': {
                    'mode': self.config.get('mode', 'local'),
                    'policy': {
                        'max_pin_attempts': self.config.get('policy', {}).get('max_pin_attempts', 4),
                        'lockout_seconds': self.config.get('policy', {}).get('lockout_seconds', 600),
                        'default_reauth_after_seconds': self.config.get('policy', {}).get('default_reauth_after_seconds', 28800),
                    },
                },
                'users': users,
            }

    def _housekeeper_loop(self) -> None:
        interval_s = max(0.1, int(self.config.get('policy', {}).get('lock_check_interval_ms', 250)) / 1000.0)
        while not self.stop_event.is_set():
            with self.lock:
                now = now_ts()
                expired_tokens = [token for token, exp in self.admin_tokens.items() if exp <= now]
                for token in expired_tokens:
                    self.admin_tokens.pop(token, None)
                self.state['registration']['admin_session_valid'] = bool(self.admin_tokens)

                if self.state['registration'].get('active') and int(self.state['registration'].get('expires_at') or 0) <= now:
                    self.state['registration']['active'] = False
                    self.state['registration']['expires_at'] = 0
                    self.state['registration']['pending_tag'] = None

                if int(self.state['auth'].get('locked_until_ts') or 0) <= now and int(self.state['auth'].get('locked_until_ts') or 0) != 0:
                    self.state['auth']['locked_until_ts'] = 0
                    self.state['auth']['failed_attempts'] = 0
                    if not self.state['lock'].get('authenticated') and self.state['ui'].get('screen') != 'pin':
                        self.state['ui']['message'] = 'System gesperrt: Bitte Karte.'

                self.persist_state()
            time.sleep(interval_s)


def make_handler(runtime: KienzleLockRuntime):
    lock_page = (WWW_PATH / 'lock.html').read_text(encoding='utf-8')
    register_page = (WWW_PATH / 'register.html').read_text(encoding='utf-8')

    class Handler(BaseHTTPRequestHandler):
        server_version = 'kienzlelock/1.3'

        def log_message(self, fmt: str, *args: Any) -> None:
            LOG.info('%s - %s', self.address_string(), fmt % args)

        def _send(self, status: int, body: bytes, content_type: str) -> None:
            self.send_response(status)
            self.send_header('Content-Type', content_type)
            self.send_header('Cache-Control', 'no-store')
            self.send_header('Pragma', 'no-cache')
            self.send_header('Content-Length', str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def _send_json(self, status: int, payload: Dict[str, Any]) -> None:
            self._send(status, json.dumps(payload).encode('utf-8'), 'application/json; charset=utf-8')

        def _admin_token(self) -> str:
            return self.headers.get('X-Kienzlelock-Admin-Token', '').strip()

        def do_GET(self) -> None:
            if self.path in ('/', '/lock'):
                self._send(HTTPStatus.OK, lock_page.encode('utf-8'), 'text/html; charset=utf-8')
                return
            if self.path == '/register':
                self._send(HTTPStatus.OK, register_page.encode('utf-8'), 'text/html; charset=utf-8')
                return
            if self.path == '/api/lock/state':
                self._send_json(HTTPStatus.OK, runtime.public_state())
                return
            if self.path == '/api/admin/registration/status':
                self._send_json(HTTPStatus.OK, {'ok': True, **runtime.admin_status(self._admin_token())})
                return
            if self.path.startswith('/assets/'):
                rel = self.path.lstrip('/')
                asset = WWW_PATH / rel[len('assets/'):]
                asset = WWW_PATH / rel
                try:
                    body = asset.read_bytes()
                except Exception:
                    self._send_json(HTTPStatus.NOT_FOUND, {'ok': False, 'error': 'not_found'})
                    return
                suffix = asset.suffix.lower()
                if suffix == '.png':
                    ctype = 'image/png'
                elif suffix == '.svg':
                    ctype = 'image/svg+xml'
                elif suffix in ('.jpg', '.jpeg'):
                    ctype = 'image/jpeg'
                else:
                    ctype = 'application/octet-stream'
                self._send(HTTPStatus.OK, body, ctype)
                return
            self._send_json(HTTPStatus.NOT_FOUND, {'ok': False, 'error': 'not_found'})

        def do_POST(self) -> None:
            try:
                payload = read_body(self)
            except Exception:
                self._send_json(HTTPStatus.BAD_REQUEST, {'ok': False, 'error': 'bad_json'})
                return

            if self.path == '/api/lock/pin':
                pin = str(payload.get('pin', ''))
                self._send_json(HTTPStatus.OK, runtime.submit_pin(pin))
                return

            if self.path == '/api/admin/login':
                password = str(payload.get('password', ''))
                result = runtime.admin_login(password)
                status = HTTPStatus.OK if result.get('ok') else HTTPStatus.UNAUTHORIZED
                self._send_json(status, result)
                return

            if self.path == '/api/admin/registration/start':
                result = runtime.registration_start(self._admin_token())
            elif self.path == '/api/admin/registration/commit':
                result = runtime.registration_commit(self._admin_token(), payload)
            elif self.path == '/api/admin/registration/cancel':
                result = runtime.registration_cancel(self._admin_token())
            elif self.path == '/api/admin/registration/update':
                result = runtime.registration_update(self._admin_token(), payload)
            elif self.path == '/api/admin/registration/delete':
                result = runtime.registration_delete(self._admin_token(), payload)
            else:
                self._send_json(HTTPStatus.NOT_FOUND, {'ok': False, 'error': 'not_found'})
                return

            if result.get('ok'):
                status = HTTPStatus.OK
            elif result.get('error') == 'unauthorized':
                status = HTTPStatus.UNAUTHORIZED
            else:
                status = HTTPStatus.BAD_REQUEST
            self._send_json(status, result)

    return Handler


def main() -> None:
    logging.basicConfig(level=logging.INFO, format='%(asctime)s %(levelname)s %(name)s: %(message)s')
    runtime = KienzleLockRuntime()
    runtime.start()

    bind = str(runtime.config.get('local', {}).get('bind', '127.0.0.1'))
    port = int(runtime.config.get('local', {}).get('port', 8443))
    handler = make_handler(runtime)

    httpd = ThreadingHTTPServer((bind, port), handler)
    cert_path = runtime.config.get('local', {}).get('tls_cert') or runtime.config.get('tls_cert')
    key_path = runtime.config.get('local', {}).get('tls_key') or runtime.config.get('tls_key')
    ssl_ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    ssl_ctx.load_cert_chain(certfile=str(cert_path), keyfile=str(key_path))
    httpd.socket = ssl_ctx.wrap_socket(httpd.socket, server_side=True)

    def handle_signal(signum, _frame):
        LOG.info('Signal %s empfangen, stoppe...', signum)
        runtime.stop()
        threading.Thread(target=httpd.shutdown, name='httpd-shutdown', daemon=True).start()

    signal.signal(signal.SIGTERM, handle_signal)
    signal.signal(signal.SIGINT, handle_signal)

    LOG.info('kienzlelockd lauscht auf https://%s:%s', bind, port)
    httpd.serve_forever(poll_interval=0.5)


if __name__ == '__main__':
    main()

