#!/usr/bin/env python3
import json
import os
import ssl
import time
import tkinter as tk
import urllib.request
from pathlib import Path

STATE_PATH = Path('/var/lib/kienzlelock/state.json')
VERSION_PATH = Path('/opt/kienzlelock/VERSION')
ICON_PATH = Path('/opt/kienzlelock/www/assets/kienzlelock-logo.png')
LOCAL_PORT = int(os.environ.get('KIENZLELOCK_PORT', '8443'))

try:
    from PIL import Image, ImageTk
except Exception:
    Image = None
    ImageTk = None


class OverlayApp:
    def __init__(self) -> None:
        self.version = self._read_version()
        self.visible = False
        self.grabbed = False
        self.mode = None
        self.last_message = None
        self.last_detail = None
        self.logo_image = None
        self.pin_buffer = ''

        self.root = tk.Tk()
        self.root.configure(bg='black', cursor='none')
        self.root.attributes('-fullscreen', True)
        self.root.attributes('-topmost', True)
        self.root.protocol('WM_DELETE_WINDOW', lambda: None)
        self.root.bind_all('<KeyPress>', self._on_any_key, add='+')
        self.root.bind_all('<KeyRelease>', self._on_any_key_release, add='+')

        self.screen_w = max(1, self.root.winfo_screenwidth())
        self._build_ui()
        self.root.withdraw()
        self.root.after(300, self._poll)

    def _read_version(self) -> str:
        try:
            return VERSION_PATH.read_text(encoding='utf-8').strip() or '?'
        except Exception:
            return '?'

    def _load_logo(self):
        target_w = max(140, int(self.screen_w * 0.20))
        try:
            if Image is not None and ImageTk is not None:
                img = Image.open(ICON_PATH).convert('RGBA')
                w, h = img.size
                if w <= 0 or h <= 0:
                    raise RuntimeError('ungültige Bildgröße')
                new_h = max(1, int(h * (target_w / w)))
                img = img.resize((target_w, new_h), Image.Resampling.LANCZOS)
                self.logo_image = ImageTk.PhotoImage(img)
            else:
                raw = tk.PhotoImage(file=str(ICON_PATH))
                w = max(raw.width(), 1)
                scale = max(1, int(round(w / target_w)))
                self.logo_image = raw.subsample(scale, scale)
        except Exception:
            self.logo_image = None

    def _build_ui(self) -> None:
        self._load_logo()

        self.footer = tk.Label(
            self.root,
            text=f'kienzlelock v{self.version} von Dr. Thomas Kienzle - kienzlelock.de',
            font=('Sans', 12),
            fg='#8a8a8a',
            bg='black',
            anchor='se',
            justify='right',
        )
        self.footer.place(relx=1.0, rely=1.0, anchor='se', x=-18, y=-16)

        self.container = tk.Frame(self.root, bg='black')
        self.container.place(relx=0.5, rely=0.47, anchor='center')

        self.locked_frame = tk.Frame(self.container, bg='black')
        self.locked_logo = tk.Label(self.locked_frame, bg='black')
        if self.logo_image is not None:
            self.locked_logo.config(image=self.logo_image)
        else:
            self.locked_logo.config(text='🔒', font=('Sans', 120), fg='white')
        self.locked_logo.pack(pady=(0, 34))

        self.locked_message = tk.Label(
            self.locked_frame,
            text='System gesperrt: Bitte Karte.',
            font=('Sans', 28),
            fg='white',
            bg='black',
        )
        self.locked_message.pack(pady=(0, 10))

        self.locked_detail = tk.Label(
            self.locked_frame,
            text='',
            font=('Sans', 18),
            fg='#bcbcbc',
            bg='black',
        )
        self.locked_detail.pack()

        self.pin_frame = tk.Frame(self.container, bg='black')
        self.pin_left = tk.Frame(self.pin_frame, bg='black')
        self.pin_left.pack(side='left', padx=(0, 44), anchor='center')
        self.pin_logo = tk.Label(self.pin_left, bg='black')
        if self.logo_image is not None:
            self.pin_logo.config(image=self.logo_image)
        else:
            self.pin_logo.config(text='🔒', font=('Sans', 120), fg='white')
        self.pin_logo.pack()

        self.pin_right = tk.Frame(self.pin_frame, bg='black')
        self.pin_right.pack(side='left', anchor='center')

        self.pin_message = tk.Label(
            self.pin_right,
            text='System gesperrt: Bitte Karte.',
            font=('Sans', 26),
            fg='white',
            bg='black',
            anchor='w',
            justify='left',
        )
        self.pin_message.pack(anchor='w', pady=(0, 10))

        self.pin_detail = tk.Label(
            self.pin_right,
            text='',
            font=('Sans', 18),
            fg='#bcbcbc',
            bg='black',
            anchor='w',
            justify='left',
        )
        self.pin_detail.pack(anchor='w', pady=(0, 16))

        self.pin_var = tk.StringVar(value='')
        self.pin_entry = tk.Entry(
            self.pin_right,
            textvariable=self.pin_var,
            show='•',
            font=('Sans', 28),
            justify='center',
            width=12,
            bg='#101010',
            fg='white',
            insertbackground='white',
            relief='flat',
            state='readonly',
            readonlybackground='#101010',
        )
        self.pin_entry.pack(anchor='w', pady=(0, 14), ipadx=10, ipady=10)

        keypad = tk.Frame(self.pin_right, bg='black')
        keypad.pack(anchor='w')
        buttons = ['1','2','3','4','5','6','7','8','9','←','0','OK']
        for idx, label in enumerate(buttons):
            row = idx // 3
            col = idx % 3
            btn = tk.Button(
                keypad,
                text=label,
                command=self._make_button_command(label),
                font=('Sans', 20),
                width=5,
                height=2,
                bg='#1c1c1c',
                fg='white',
                activebackground='#333333',
                activeforeground='white',
                relief='flat',
                bd=0,
            )
            btn.grid(row=row, column=col, padx=8, pady=8)

    def _make_button_command(self, label: str):
        def _cmd() -> None:
            if self.mode != 'pin':
                return
            if label == 'OK':
                self.submit_pin()
            elif label == '←':
                self._pin_backspace()
            else:
                self._pin_append(label)
            self._focus_root()
        return _cmd

    def _focus_root(self):
        try:
            self.root.focus_force()
        except Exception:
            pass

    def _pin_sync(self):
        self.pin_var.set(self.pin_buffer)

    def _pin_clear(self):
        self.pin_buffer = ''
        self._pin_sync()

    def _pin_append(self, digit: str):
        if len(self.pin_buffer) >= 32:
            return
        self.pin_buffer += digit
        self._pin_sync()

    def _pin_backspace(self):
        if self.pin_buffer:
            self.pin_buffer = self.pin_buffer[:-1]
            self._pin_sync()

    def _on_any_key(self, event):
        if self.mode != 'pin':
            return 'break'
        key = event.keysym or ''
        char = event.char or ''
        if char and char.isdigit():
            self._pin_append(char)
            return 'break'
        if key.startswith('KP_') and len(key) == 4 and key[-1].isdigit():
            self._pin_append(key[-1])
            return 'break'
        if key in ('BackSpace', 'Delete'):
            self._pin_backspace()
            return 'break'
        if key in ('Return', 'KP_Enter'):
            self.submit_pin()
            return 'break'
        if key == 'Escape':
            self._pin_clear()
            return 'break'
        return 'break'

    def _on_any_key_release(self, _event):
        if self.mode == 'pin':
            return 'break'
        return None

    def _show(self) -> None:
        if not self.visible:
            self.root.deiconify()
            self.root.lift()
            self.root.attributes('-topmost', True)
            self.visible = True
        if not self.grabbed:
            try:
                self.root.grab_set_global()
                self.grabbed = True
            except tk.TclError:
                self.grabbed = False
        self._focus_root()

    def _hide(self) -> None:
        if self.grabbed:
            try:
                self.root.grab_release()
            except tk.TclError:
                pass
            self.grabbed = False
        if self.visible:
            self.root.withdraw()
            self.visible = False

    def _read_state(self):
        try:
            return json.loads(STATE_PATH.read_text(encoding='utf-8'))
        except Exception:
            return None

    def _submit_pin_http(self, pin: str):
        payload = json.dumps({'pin': pin}).encode('utf-8')
        req = urllib.request.Request(
            f'https://127.0.0.1:{LOCAL_PORT}/api/lock/pin',
            data=payload,
            method='POST',
            headers={'Content-Type': 'application/json'},
        )
        ctx = ssl._create_unverified_context()
        with urllib.request.urlopen(req, timeout=2.0, context=ctx) as response:
            return json.loads(response.read().decode('utf-8'))

    def submit_pin(self) -> None:
        pin = self.pin_buffer.strip()
        if not pin:
            self._focus_root()
            return
        try:
            self._submit_pin_http(pin)
        except Exception:
            pass
        finally:
            self._pin_clear()
            self._focus_root()

    def _set_mode(self, mode: str) -> None:
        if self.mode == mode:
            return
        self.locked_frame.pack_forget()
        self.pin_frame.pack_forget()
        if mode == 'pin':
            self.pin_frame.pack()
            self._pin_clear()
            self.root.after(20, self._focus_root)
        else:
            self.locked_frame.pack()
            self._pin_clear()
        self.mode = mode

    def _set_message(self, text: str) -> None:
        if self.last_message == text:
            return
        self.locked_message.config(text=text)
        self.pin_message.config(text=text)
        self.last_message = text

    def _set_detail(self, text: str) -> None:
        if self.last_detail == text:
            return
        self.locked_detail.config(text=text)
        self.pin_detail.config(text=text)
        self.last_detail = text

    def _poll(self) -> None:
        state = self._read_state()
        if not state:
            self._show()
            self._set_mode('locked')
            self._set_message('kienzlelock startet …')
            self._set_detail('')
            self.root.after(300, self._poll)
            return

        lock = state.get('lock', {})
        auth = state.get('auth', {})
        ui = state.get('ui', {})

        if lock.get('authenticated'):
            self._hide()
            self.root.after(250, self._poll)
            return

        self._show()
        wanted_mode = 'pin' if ui.get('screen') == 'pin' else 'locked'
        self._set_mode(wanted_mode)
        self._set_message(ui.get('message') or 'System gesperrt: Bitte Karte.')

        locked_until = int(auth.get('locked_until_ts') or 0)
        now = int(time.time())
        if locked_until > now:
            remaining = max(0, locked_until - now)
            mins, secs = divmod(remaining, 60)
            self._set_detail(f'Noch {mins:02d}:{secs:02d} gesperrt')
        else:
            self._set_detail('')

        self.root.after(300, self._poll)

    def run(self) -> None:
        self.root.mainloop()


if __name__ == '__main__':
    OverlayApp().run()

PYEOF
chmod 755 "${APP_DIR}/overlay.py"

