<!doctype html>
<html lang="de">
<head>
  <meta charset="utf-8">
  <title>kienzlelock-register</title>
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <style>
    body { margin: 0; font-family: sans-serif; background: #111; color: #eee; }
    .wrap { max-width: 1100px; margin: 30px auto; padding: 24px; background: #1a1a1a; border-radius: 12px; }
    h1, h2 { margin-top: 0; }
    input, button { font-size: 1rem; padding: 10px 12px; border-radius: 8px; border: 0; margin: 6px 0; }
    input { width: min(100%, 520px); background: #0f0f0f; color: #fff; }
    button { background: #2a2a2a; color: #fff; cursor: pointer; margin-right: 8px; }
    button.danger { background: #6e1f1f; }
    .row { margin-bottom: 18px; }
    .muted { color: #aaa; }
    .status { padding: 12px; background: #101010; border-radius: 8px; margin: 10px 0 18px; white-space: pre-wrap; }
    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 12px 18px; align-items: start; }
    .box { background: #141414; border-radius: 10px; padding: 14px; }
    table { width: 100%; border-collapse: collapse; margin-top: 8px; font-size: 0.95rem; }
    th, td { text-align: left; padding: 10px 8px; border-bottom: 1px solid #2a2a2a; vertical-align: top; }
    th { color: #bbb; font-weight: 600; }
    tr.active { background: #202020; }
    .small { font-size: 0.9rem; color: #aaa; }
    .readonly { opacity: 0.7; }
    .nowrap { white-space: nowrap; }
  </style>
</head>
<body>
<div class="wrap">
  <h1>kienzlelock – Tag-Registrierung und Verwaltung</h1>
  <div class="row">
    <h2>1. Admin-Login</h2>
    <input id="adminPassword" type="password" placeholder="Registrierungs-Passwort"><br>
    <button id="loginBtn">Login</button>
    <span id="loginState" class="muted"></span>
  </div>
  <div class="row grid">
    <div class="box">
      <h2>2. Neue Registrierung starten</h2>
      <button id="startBtn">Bitte jetzt neuen Tag gegenhalten</button>
      <button id="cancelBtn">Abbrechen</button>
      <div class="small">Danach unten im Bereich „Neuen Tag speichern“ übernehmen.</div>
    </div>
    <div class="box">
      <h2>3. Status</h2>
      <div id="status" class="status">Noch kein Status.</div>
    </div>
  </div>
  <div class="row box">
    <h2>4. Neuen Tag speichern</h2>
    <input id="userId" list="userList" placeholder="user_id, z. B. thomas">
    <datalist id="userList"></datalist><br>
    <input id="displayName" placeholder="Anzeigename, z. B. Thomas"><br>
    <input id="label" placeholder="Tag-Label, z. B. Schlüsselbund"><br>
    <input id="pin" type="password" inputmode="numeric" placeholder="PIN"><br>
    <input id="reauth" type="number" placeholder="reauth_after_seconds (optional)"><br>
    <button id="commitBtn">Speichern</button>
  </div>
  <div class="row box">
    <h2>5. Bestehende Registrierungen</h2>
    <div class="small">Beim Ändern der Benutzer-ID wird der ausgewählte Tag zu diesem Benutzer verschoben. Bleibt der alte Benutzer ohne Tags zurück, wird er automatisch entfernt.</div>
    <table>
      <thead><tr><th>Benutzer</th><th>Anzeigename</th><th>Label</th><th>Wert</th><th>Typ</th><th>Reauth</th><th class="nowrap">Aktion</th></tr></thead>
      <tbody id="registrationsBody"><tr><td colspan="7" class="muted">Noch keine Daten geladen.</td></tr></tbody>
    </table>
  </div>
  <div class="row box">
    <h2>6. Auswahl bearbeiten</h2>
    <div id="editHint" class="muted">Bitte oben einen Eintrag auswählen.</div>
    <div id="editBox" style="display:none;">
      <div id="selectedMeta" class="small"></div>
      <input id="editTagId" class="readonly" readonly placeholder="tag_id"><br>
      <input id="editUserId" list="userList" placeholder="user_id"><br>
      <input id="editDisplayName" placeholder="Anzeigename"><br>
      <input id="editLabel" placeholder="Tag-Label"><br>
      <input id="editPin" type="password" inputmode="numeric" placeholder="Neue PIN (leer = unverändert)"><br>
      <input id="editReauth" type="number" placeholder="reauth_after_seconds (leer = Standard)"><br>
      <button id="saveEditBtn">Änderungen speichern</button>
      <button id="deleteBtn" class="danger">Tag löschen</button>
    </div>
  </div>
</div>
<script>
let adminToken = sessionStorage.getItem('kienzlelock_admin_token') || '';
let registrationsById = {};
let selectedTagId = null;
async function api(url, method='GET', payload=null) {
  const opts = {method, headers: {}};
  if (adminToken) opts.headers['X-Kienzlelock-Admin-Token'] = adminToken;
  if (payload !== null) { opts.headers['Content-Type'] = 'application/json'; opts.body = JSON.stringify(payload); }
  const res = await fetch(url, opts);
  let data = {};
  try { data = await res.json(); } catch (_err) {}
  if (!data || typeof data !== 'object') data = {};
  data.http_status = res.status;
  return data;
}
function setLoginState(text) { document.getElementById('loginState').textContent = text; }
function truncateMiddle(value, keep=8) { value = String(value || ''); if (value.length <= keep * 2 + 1) return value; return value.slice(0, keep) + '…' + value.slice(-keep); }
async function login() {
  const password = document.getElementById('adminPassword').value;
  const result = await api('/api/admin/login', 'POST', {password});
  if (result.ok) { adminToken = result.token; sessionStorage.setItem('kienzlelock_admin_token', adminToken); setLoginState('Login ok'); document.getElementById('adminPassword').value = ''; }
  else { setLoginState('Login fehlgeschlagen'); }
  await refresh();
}
async function startRegistration() { const result = await api('/api/admin/registration/start', 'POST', {}); if (!result.ok) alert('Start fehlgeschlagen: ' + (result.error || 'unbekannt')); await refresh(); }
async function cancelRegistration() { const result = await api('/api/admin/registration/cancel', 'POST', {}); if (!result.ok) alert('Abbrechen fehlgeschlagen: ' + (result.error || 'unbekannt')); await refresh(); }
async function commitRegistration() {
  const payload = { user_id: document.getElementById('userId').value.trim(), display_name: document.getElementById('displayName').value.trim(), label: document.getElementById('label').value.trim(), pin: document.getElementById('pin').value, reauth_after_seconds: document.getElementById('reauth').value };
  const result = await api('/api/admin/registration/commit', 'POST', payload);
  if (!result.ok) alert('Speichern fehlgeschlagen: ' + (result.error || 'unbekannt')); else { alert('Gespeichert.'); document.getElementById('pin').value = ''; }
  await refresh();
}
function selectRegistration(tagId) {
  const row = registrationsById[tagId]; if (!row) return;
  selectedTagId = tagId;
  document.getElementById('editHint').style.display = 'none'; document.getElementById('editBox').style.display = 'block';
  document.getElementById('editTagId').value = row.tag_id || ''; document.getElementById('editUserId').value = row.user_id || ''; document.getElementById('editDisplayName').value = row.display_name || ''; document.getElementById('editLabel').value = row.label || ''; document.getElementById('editPin').value = ''; document.getElementById('editReauth').value = row.reauth_after_seconds === '' ? '' : (row.reauth_after_seconds ?? '');
  document.getElementById('selectedMeta').textContent = `Typ: ${row.type || '---'} · Wert: ${row.value || '---'} · Tag-ID: ${row.tag_id || '---'}`;
  renderRegistrations(Object.values(registrationsById));
}
async function saveEdit() {
  if (!selectedTagId) return;
  const payload = { tag_id: selectedTagId, user_id: document.getElementById('editUserId').value.trim(), display_name: document.getElementById('editDisplayName').value.trim(), label: document.getElementById('editLabel').value.trim(), pin: document.getElementById('editPin').value, reauth_after_seconds: document.getElementById('editReauth').value };
  const result = await api('/api/admin/registration/update', 'POST', payload);
  if (!result.ok) alert('Aktualisieren fehlgeschlagen: ' + (result.error || 'unbekannt')); else { alert('Aktualisiert.'); document.getElementById('editPin').value = ''; }
  await refresh();
}
async function deleteSelected() {
  if (!selectedTagId) return;
  const row = registrationsById[selectedTagId];
  const label = row ? `${row.display_name || row.user_id} / ${row.label || row.value}` : selectedTagId;
  if (!confirm(`Diesen Tag wirklich löschen?

${label}`)) return;
  const result = await api('/api/admin/registration/delete', 'POST', {tag_id: selectedTagId});
  if (!result.ok) alert('Löschen fehlgeschlagen: ' + (result.error || 'unbekannt')); else { selectedTagId = null; document.getElementById('editBox').style.display = 'none'; document.getElementById('editHint').style.display = 'block'; alert('Gelöscht.'); }
  await refresh();
}
function renderRegistrations(rows) {
  const tbody = document.getElementById('registrationsBody'); tbody.innerHTML = '';
  if (!adminToken) { tbody.innerHTML = '<tr><td colspan="7" class="muted">Bitte zuerst oben einloggen.</td></tr>'; return; }
  if (!rows.length) { tbody.innerHTML = '<tr><td colspan="7" class="muted">Keine Registrierungen vorhanden.</td></tr>'; return; }
  rows.forEach((row) => {
    const tr = document.createElement('tr'); if (selectedTagId && row.tag_id === selectedTagId) tr.className = 'active';
    tr.innerHTML = `<td>${escapeHtml(row.user_id || '')}</td><td>${escapeHtml(row.display_name || '')}</td><td>${escapeHtml(row.label || '')}</td><td title="${escapeHtml(row.value || '')}">${escapeHtml(truncateMiddle(row.value || ''))}</td><td>${escapeHtml(row.type || '')}</td><td>${escapeHtml(String(row.reauth_after_seconds ?? ''))}</td><td class="nowrap"><button data-tag-id="${escapeHtml(row.tag_id || '')}">Bearbeiten</button></td>`;
    tbody.appendChild(tr);
  });
  tbody.querySelectorAll('button[data-tag-id]').forEach((btn) => btn.addEventListener('click', () => selectRegistration(btn.dataset.tagId)));
}
function escapeHtml(value) { return String(value).replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;'); }
async function refresh() {
  try {
    const data = await api('/api/admin/registration/status');
    const state = data.state || {}; const registration = state.registration || {}; const reader = state.reader || {}; const ui = state.ui || {}; const users = data.users || []; const regs = Array.isArray(data.registrations) ? data.registrations : [];
    if (data.admin_authorized) setLoginState('Login ok');
    const list = document.getElementById('userList'); list.innerHTML = ''; users.forEach((user) => { const opt = document.createElement('option'); opt.value = user.user_id; opt.label = user.display_name || user.user_id; list.appendChild(opt); });
    registrationsById = {}; regs.forEach((r) => registrationsById[r.tag_id] = r);
    if (selectedTagId && !registrationsById[selectedTagId]) { selectedTagId = null; document.getElementById('editBox').style.display = 'none'; document.getElementById('editHint').style.display = 'block'; }
    renderRegistrations(regs);
    const pending = registration.pending_tag ? `${registration.pending_tag.type} / ${registration.pending_tag.value} / ${registration.pending_tag.label}` : '---';
    document.getElementById('status').textContent = `Admin-Session: ${registration.admin_session_valid ? 'aktiv' : 'inaktiv'}
Registrierung aktiv: ${registration.active ? 'ja' : 'nein'}
Reader online: ${reader.online ? 'ja' : 'nein'}
Reader: ${reader.reader_name || '---'}
Pending Tag: ${pending}
Vorhandene Tags: ${regs.length}
UI-Meldung: ${ui.message || '---'}`;
  } catch (_err) { document.getElementById('status').textContent = 'Server nicht erreichbar.'; }
}
document.getElementById('loginBtn').addEventListener('click', login);
document.getElementById('startBtn').addEventListener('click', startRegistration);
document.getElementById('cancelBtn').addEventListener('click', cancelRegistration);
document.getElementById('commitBtn').addEventListener('click', commitRegistration);
document.getElementById('saveEditBtn').addEventListener('click', saveEdit);
document.getElementById('deleteBtn').addEventListener('click', deleteSelected);
setInterval(refresh, 1200); refresh();
</script>
</body>
</html>

