  <title>kienzlelock-lock</title>
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <style>
    html, body { margin: 0; width: 100%; height: 100%; background: #000; color: #fff; font-family: sans-serif; overflow: hidden; }
    .center { min-height: 100%; display: flex; align-items: center; justify-content: center; text-align: center; flex-direction: column; }
    .icon { width: 220px; height: auto; margin-bottom: 42px; user-select: none; pointer-events: none; }
    .msg { font-size: 2rem; margin-bottom: 10px; }
    .detail { color: #bfbfbf; font-size: 1.1rem; min-height: 1.4rem; }
    .footer { position: fixed; right: 18px; bottom: 14px; color: #8a8a8a; font-size: 0.9rem; white-space: nowrap; text-align: right; }
  </style>
</head>
<body>
  <div class="center">
    <img class="icon" src="/assets/kienzlelock-logo.png" alt="">
    <div id="msg" class="msg">System gesperrt: Bitte Karte.</div>
    <div id="detail" class="detail"></div>
  </div>
  <div id="footer" class="footer">kienzlelock v? von Dr. Thomas Kienzle - kienzlelock.de</div>
<script>
async function refresh() {
  try {
    const res = await fetch('/api/lock/state', {cache: 'no-store'});
    const data = await res.json();
    const state = data.state || {}; const lock = state.lock || {}; const auth = state.auth || {}; const ui = state.ui || {};
    document.getElementById('msg').textContent = ui.message || 'System gesperrt: Bitte Karte.';
    document.getElementById('footer').textContent = `kienzlelock v${data.version || '?'} von Dr. Thomas Kienzle - kienzlelock.de`;
    if ((auth.locked_until_ts || 0) * 1000 > Date.now()) {
      const sec = Math.max(0, auth.locked_until_ts - Math.floor(Date.now() / 1000));
      const mm = String(Math.floor(sec / 60)).padStart(2, '0');
      const ss = String(sec % 60).padStart(2, '0');
      document.getElementById('detail').textContent = `Noch ${mm}:${ss} gesperrt`;
    } else {
      document.getElementById('detail').textContent = lock.authenticated ? 'System freigegeben.' : '';
    }
  } catch (_err) {}
}
setInterval(refresh, 1000); refresh();
</script>
</body>
</html>

EOF

cat > /usr/local/bin/kienzlelock-hash <<'EOF'
#!/usr/bin/env python3
import getpass
import hashlib
import secrets
secret = getpass.getpass('Passwort/PIN: ')
salt = secrets.token_hex(16)
iterations = 200_000
digest = hashlib.pbkdf2_hmac('sha256', secret.encode(), salt.encode(), iterations).hex()
print(f'pbkdf2_sha256${iterations}${salt}${digest}')
EOF
chmod 755 /usr/local/bin/kienzlelock-hash

cat > /usr/local/bin/kienzlelock-overlay-launcher.sh <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
while [[ ! -f /var/lib/kienzlelock/state.json ]]; do
  sleep 0.5
done
while true; do
  /opt/kienzlelock/venv/bin/python /opt/kienzlelock/overlay.py >> /tmp/kienzlelock-overlay.log 2>&1 || true
  sleep 1
done
EOF
chmod 755 /usr/local/bin/kienzlelock-overlay-launcher.sh

cat > /usr/local/bin/kienzlelock-browser-controller.sh <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
echo "kienzlelock v1.3 nutzt den nativen Overlay-Lockscreen. Browser nur noch für /register." >&2
exit 0
EOF
chmod 755 /usr/local/bin/kienzlelock-browser-controller.sh

cat > "${SYSTEMD_DIR}/kienzlelockd.service" <<'EOF'
[Unit]
Description=kienzlelock daemon
After=network.target pcscd.socket
Wants=pcscd.socket

[Service]
Type=simple
ExecStart=/opt/kienzlelock/venv/bin/python /opt/kienzlelock/daemon.py
Restart=always
RestartSec=2
User=root
Group=root
Environment=PYTHONUNBUFFERED=1

[Install]
WantedBy=multi-user.target
EOF

cat > "${AUTOSTART_DIR}/kienzlelock-overlay.desktop" <<'EOF'
[Desktop Entry]
Type=Application
Name=kienzlelock Overlay
Exec=/usr/local/bin/kienzlelock-overlay-launcher.sh
OnlyShowIn=XFCE;
X-GNOME-Autostart-enabled=true
Terminal=false
NoDisplay=false
EOF

rm -f "${AUTOSTART_DIR}/kienzlelock-browser.desktop"
rm -f "/home/${APP_USER}/.config/autostart/kienzlelock-browser.desktop" 2>/dev/null || true

mkdir -p /etc/lightdm/lightdm.conf.d
cat > /etc/lightdm/lightdm.conf.d/90-kienzlelock-autologin.conf <<EOF
[Seat:*]
autologin-user=${APP_USER}
autologin-session=xfce
EOF

python3 -m py_compile "${APP_DIR}/daemon.py" "${APP_DIR}/overlay.py"

chown -R root:root "${APP_DIR}" "${ETC_DIR}" "${VAR_DIR}"

systemctl enable pcscd.socket
systemctl daemon-reload
systemctl enable kienzlelockd.service
systemctl restart pcscd.socket
systemctl restart kienzlelockd.service

echo
echo "Fertig."
echo "Version: ${APP_VERSION}"
echo "Daemon-Status:"
systemctl --no-pager --full status kienzlelockd.service | sed -n "1,12p" || true
echo
echo "Wichtige Pfade:"
echo "  config.json : ${ETC_DIR}/config.json"
echo "  state.json  : ${VAR_DIR}/state.json"
echo "  Registrierung (lokal): https://127.0.0.1:8443/register"
echo
